#include<bits/stdc++.h>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
inline bool rd(){char c;do c=getchar();while(c!='1'&&c!='0');return c=='1';}
bool f1;
const int N=2e4+5,NN=52;typedef long long ll;
const ll INF=0x3f3f3f3f3f3f3f3fll;
int n,m,K,a[N],lst[NN],B[N][NN];bool w[N][NN];
ll dp[N],g[N],s[N];deque<int> q[NN];
bool f2;
int main()
{
//	printf("Mem :: %.6lf\n",1.*(&f1-&f2)/1024/1024);
	n=read();m=read();K=read();
	rep(1,m,i)s[i]=s[i-1]+(a[i]=read());
	rep(1,n,i)rep(1,m,j)w[j][i]=rd();
	rep(1,m,i)
	{
		rep(1,n,j)if(!w[i][j])lst[j]=i;
		int cnt=0;rep(1,n,j)if(!lst[j])++cnt;
		dp[i]=s[i]*cnt;
		memcpy(B[i],lst,sizeof(lst));
		sort(B[i]+1,B[i]+n+1);B[i][n+1]=i;
	}
//	printf("%d :: ",1);rep(1,m,i)printf("%lld ",dp[i]);puts("");
	printf("%lld\n",dp[m]);
	dp[0]=INF;rep(2,K,le)
	{
		memcpy(g,dp,sizeof(dp));
		memset(dp,0x3f,sizeof(dp));
		rep(0,n,j)q[j].clear();
		rep(le,m,i)
		{
			rep(0,n,j)
			{
				rep(B[i-1][j+1],B[i][j+1]-1,k){while(!q[j].empty()&&g[q[j].back()]-s[q[j].back()]*j>g[k]-s[k]*j)q[j].pop_back();q[j].push_back(k);}
				while(!q[j].empty()&&q[j].front()<B[i][j])q[j].pop_front(); if(B[i][j]==B[i][j+1]||q[j].empty())continue;
				int k=q[j].front();dp[i]=min(dp[i],g[k]+(s[i]-s[k])*j);
			}
//			rep(0,n,j)
//			{
//				if(B[i][j]==B[i][j+1])continue;
//				rep(B[i][j],B[i][j+1]-1,k)dp[i]=min(dp[i],g[k]+(s[i]-s[k])*j);
//			}
		}
//		printf("%d :: ",le);rep(1,m,i)printf("%lld ",dp[i]>10000?-1ll:dp[i]);puts("");
		printf("%lld\n",dp[m]);
	}
	return 0;
}
